// Corner brackets HUD element. Per-pixel SDF: for each output pixel,
// sample the running source and check whether it's on any detection's
// L-shaped bracket arm. If so, blend the overlay colour. Edit the WGSL
// to change arm length, line thickness, or bracket shape (e.g. extend
// arms across the full edge for a 'crosshair-style' bracket).

struct U {
    color_r: f32,
    color_g: f32,
    color_b: f32,
    alpha: f32,
    arm_fraction: f32,
    thickness: f32,
    blob_count: u32,
    _pad0: u32,
};

struct Detection {
    x: f32,
    y: f32,
    width: f32,
    height: f32,
};

@group(0) @binding(0) var<uniform> u: U;
@group(0) @binding(1) var<storage, read> detections: array<Detection>;
@group(0) @binding(2) var source_tex: texture_2d<f32>;
@group(0) @binding(3) var src_sampler: sampler;
@group(0) @binding(4) var output_tex: texture_storage_2d<rgba16float, write>;

@compute @workgroup_size(16, 16)
fn cs_main(@builtin(global_invocation_id) gid: vec3<u32>) {
    let dims = textureDimensions(output_tex);
    if gid.x >= dims.x || gid.y >= dims.y { return; }
    let uv = (vec2<f32>(gid.xy) + 0.5) / vec2<f32>(dims);
    var src = textureSampleLevel(source_tex, src_sampler, uv, 0.0);

    var on_arm = false;
    let n = min(u.blob_count, 32u);
    for (var i: u32 = 0u; i < n; i = i + 1u) {
        let d = detections[i];
        if d.width < 0.0001 && d.height < 0.0001 { continue; }

        let arm = min(d.width, d.height) * u.arm_fraction;
        let t = u.thickness * 0.5;

        let x0 = d.x;
        let y0 = d.y;
        let x1 = d.x + d.width;
        let y1 = d.y + d.height;

        // Top-left corner: arms going right and down.
        let tl_h = uv.x >= x0 && uv.x <= x0 + arm && abs(uv.y - y0) <= t;
        let tl_v = uv.y >= y0 && uv.y <= y0 + arm && abs(uv.x - x0) <= t;
        // Top-right.
        let tr_h = uv.x >= x1 - arm && uv.x <= x1 && abs(uv.y - y0) <= t;
        let tr_v = uv.y >= y0 && uv.y <= y0 + arm && abs(uv.x - x1) <= t;
        // Bottom-left.
        let bl_h = uv.x >= x0 && uv.x <= x0 + arm && abs(uv.y - y1) <= t;
        let bl_v = uv.y >= y1 - arm && uv.y <= y1 && abs(uv.x - x0) <= t;
        // Bottom-right.
        let br_h = uv.x >= x1 - arm && uv.x <= x1 && abs(uv.y - y1) <= t;
        let br_v = uv.y >= y1 - arm && uv.y <= y1 && abs(uv.x - x1) <= t;

        if tl_h || tl_v || tr_h || tr_v || bl_h || bl_v || br_h || br_v {
            on_arm = true;
            break;
        }
    }

    if on_arm {
        let a = u.alpha;
        src = vec4<f32>(
            mix(src.r, u.color_r, a),
            mix(src.g, u.color_g, a),
            mix(src.b, u.color_b, a),
            src.a,
        );
    }
    textureStore(output_tex, vec2<i32>(gid.xy), src);
}
